import { Component, h, Prop, Element, Listen, Event, EventEmitter } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { getColorClass, getContainerClass, getLabelClass, getMediaClass } from './wdpr-secondary-quick-action-item.utils';

@Component({
  tag: 'wdpr-secondary-quick-action-item',
  shadow: true,
})
export class WdprSecondaryQuickActionItem {
  @Element() el: HTMLWdprSecondaryQuickActionItemElement;

  @Prop() label!: string;
  @Prop({ reflect: true }) showMedia: boolean = false;
  @Prop({ reflect: true }) showBackground: boolean = false;
  @Prop({ reflect: true }) mediaSrc?: string | null = null;
  @Prop({ reflect: true }) customLabelClass?: string | null = '';

  @Prop({ reflect: true }) disabled?: boolean = false;
  @Prop({ reflect: true }) selected?: boolean = false;

  @Event({ eventName: 'itemSelected' }) itemSelected: EventEmitter<boolean>;

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ENTER || ev.key == KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      this._itemClick();
    }

    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  private get _labelClass(): string {
    return getLabelClass(this._colorClass, this.customLabelClass);
  }

  private get _colorClass(): string {
    return getColorClass(this.disabled);
  }

  private get _containerClass(): string {
    return getContainerClass(this.showBackground);
  }

  private get _mediaClass(): string {
    return getMediaClass(this.showBackground);
  }

  private _itemClick() {
    if (this.disabled) return;

    this.selected = !this.selected;
    this.itemSelected.emit(this.selected);
  }

  render() {
    return (
      <div
        class={this._containerClass}
        tabIndex={this.disabled ? -1 : 0}
        role="button"
        aria-pressed={this.selected ? 'true' : 'false'}
        aria-disabled={this.disabled ? 'true' : undefined}
        onClick={this._itemClick.bind(this)}
      >
        {this.showMedia && (
          <div class={this._mediaClass}>
            <wdpr-media
              src={this.mediaSrc}
              alt={this.label}
              fade={true}
              aspect="square"
              shape="flat"
              objectFit="fill"
              landscapeRatio="16:9"
              portraitRatio="3:4"
            />
          </div>
        )}

        <div class={this._labelClass}>
          {this.label}
        </div>
      </div>
    );
  }
}
